export function createEl (tag, props, children) {
  const $el = document.createElement(tag);
  if (props)
    Object.entries(props).forEach(([name, val]) => {
      if (name === 'style')
        return Object.assign($el.style, val);
      $el[name] = val;
    });

  if (children) {
    if (Array.isArray(children))
      children.forEach($child => $el.append($child));
    else if (typeof children === 'string' || typeof children === 'number')
      $el.textContent = children;
  }
  return $el;
}

const SI_PREFIX = ['', 'K', 'M', 'G', 'T', 'P', 'E', 'Z', 'Y'];
export function SI (int, maximumFractionDigits = 1) {
  int = Number(int);
  for (var i = 0, nat = int; i < SI_PREFIX.length - 1; i++) {
    nat = int / 1000;
    if (nat < 1)
      break;
    int = nat;
  }
  int = int < 10 ? int.toLocaleString('en-GB', { maximumFractionDigits }) : Math.round(int);
  return `${ int }${ SI_PREFIX[i] }`;
}

export function number (v, fract = 2) {
  return v.toLocaleString('en-GB', { maximumFractionDigits: fract }).replace(/,/g, ' ');
}